class Rectangle {
private:
 int width, height;
public:
 Rectangle(int w, int h) : width(w), height(h) {}

 // Friend function declaration
 friend int calculateArea(Rectangle& r);
};

// Friend function definition (not a member)
int calculateArea(Rectangle& r) {
 // Can access private members directly
 return r.width * r.height;
}

int main() {
 Rectangle rect(10, 5);
 int area = calculateArea(rect); // 50
 return 0;
}

class Teacher {
private:
 string salary;
 string privateNotes;
public:
 Teacher(string s) : salary(s), privateNotes("Confidential") {}

 // Granting friendship to Student class
 friend class Student;
};

class Student {
public:
 void displayTeacherInfo(Teacher& t) {
 // Can access all private members of Teacher
 cout << "Salary: " << t.salary << endl;
 cout << "Notes: " << t.privateNotes << endl;
 }
};

int main() {
 Teacher t("50000");
 Student s;
 s.displayTeacherInfo(t);
 return 0;
}

class Base {
protected:
 int protectedData = 100;
 void protectedMethod() {
 cout << "Protected method called" << endl;
 }
};

class Derived : public Base {
public:
 // Using declaration to bring protected member into scope
 using Base::protectedData;
 using Base::protectedMethod;

 void accessBaseMembers() {
 // Now accessible - becomes public in Derived
 cout << "Data: " << protectedData << endl;
 protectedMethod();
 }
};

int main() {
 Derived d;
 d.accessBaseMembers();
 d.protectedData = 200; // Now accessible!
 d.protectedMethod(); // Now accessible!
 return 0;
}
